// Lot inventory — source of truth for the /available-lots/ page.
//
// Two flavors of lots, both displayed in the lots table:
//   1. MANUAL LOTS — Curtis-curated raw lots from developer pricing sheets
//      (e.g., Hawks Landing Div 4 pricing PDF, Granite Creek Block 4/5/7/12).
//      Edit the `manualLots` array below directly.
//   2. PIPELINE LOTS — auto-generated by scripts/sync-odyssey-jobs.mjs from
//      the Job Progress sheet (specs with dig date > 90 days out, where the
//      plan is still flexible). Don't edit `generatedPipelineLots` by hand —
//      edit the sheet and re-run the sync. See `.claude/skills/sync-odyssey-jobs/SKILL.md`.
//
// Status legend:
//   'available'      — open for sale, primary CTA
//   'reserved'       — buyer in early conversation, not yet under contract
//   'under-contract' — purchase agreement signed, not yet closed
//   'sold'           — closed; keep visible briefly for activity signal,
//                       then remove after ~30 days
//
// Pricing: leave `price` undefined to show "Coming Soon" instead of $.

import { generatedMasterLots } from './_generatedMasterLots';

export type LotStatus = 'available' | 'spec-in-progress' | 'reserved' | 'under-contract' | 'sold';

export interface Lot {
  id: string;                  // Stable unique id, e.g. 'hawks-landing-l13b10'
  communitySlug: string;       // Matches Community.slug in communities.ts
  lotNumber: string;           // Display label ("Lot 13, Block 10")
  parcelNumber?: string;       // County parcel id (RPB...) — internal reference
  address?: string;            // Street address
  acres?: number;              // Lot size in acres
  sqFt?: number;               // Alt lot size in sq ft (sub-acre lots)
  price?: number;              // USD asking price for the raw lot
  status: LotStatus;
  compatiblePlans?: string[];  // Slugs from plans.ts — plans that fit (or empty = all)
  notes?: string;              // Buyer-facing note
}

