// Lots are sourced from the master Google Sheet (1ES3Jjgz…) via the Apps
// Script API and synced at build time by scripts/sync-lots-from-master-sheet.mjs.
// `manualLots` is kept around as a legacy/fallback layer but is no longer
// the primary source — edit the SHEET to change website lot data.
export const lots: Lot[] = generatedMasterLots;

// Status visibility on the public /available-lots/ pages.
// - 'spec-in-progress' lots live on /quick-move-ins/, NOT on /available-lots/
// - 'sold' lots are removed entirely (no need to surface dead inventory)
// - 'available', 'reserved', 'under-contract' all show with appropriate badges
//   (reserved + under-contract are kept visible as activity signals)
const HIDE_FROM_AVAILABLE_LOTS: Set<LotStatus> = new Set(['spec-in-progress', 'sold']);

// Helper: lots in a community, filtered to only those buyers should see on
// /available-lots/, in display order — available first, then reserved,
// under-contract.
export function lotsByCommunity(slug: string): Lot[] {
  const statusOrder: Record<LotStatus, number> = {
    'available':         0,
    'spec-in-progress':  1,
    'reserved':          2,
    'under-contract':    3,
    'sold':              4,
  };
  return lots
    .filter(l => l.communitySlug === slug && !HIDE_FROM_AVAILABLE_LOTS.has(l.status))
    .sort((a, b) =>
      statusOrder[a.status] - statusOrder[b.status]
      || a.lotNumber.localeCompare(b.lotNumber, undefined, { numeric: true })
    );
}

// All lots (unfiltered) — for internal/admin contexts that need to see
// everything regardless of status.
export function allLotsByCommunity(slug: string): Lot[] {
  return lots.filter(l => l.communitySlug === slug);
}

// Helper: count lots per community by status (used in /available-lots/ stats bar)
export function lotCountByStatus(slug: string) {
  const counts: Record<LotStatus, number> = {
    available: 0, 'spec-in-progress': 0, reserved: 0, 'under-contract': 0, sold: 0,
  };
  for (const l of lots) {
    if (l.communitySlug === slug) counts[l.status]++;
  }
  return counts;
}
